-- Demo approved reviews (average to good quality, 3-5 stars)
INSERT OR IGNORE INTO reviews (id, user_id, service_id, rating, comment, is_verified, created_at, updated_at, booking_id, text, images, status) VALUES
  (3001, 1001, NULL, 5, 'Very happy with the cleaning service. My home looks brand new!', 1, datetime('now', '-24 days'), datetime('now'), 2001, 'Very happy with the cleaning service. The team arrived on time and worked efficiently. My home looks brand new and smells amazing. Will definitely book again!', '[]', 'approved'),
  (3002, 1002, NULL, 4, 'Good deep clean, thorough work on the kitchen and bathrooms.', 1, datetime('now', '-38 days'), datetime('now'), 2002, 'Good deep clean overall. The team was thorough with the kitchen and bathrooms. Missed a spot behind the fridge but otherwise very satisfied. Professional and polite staff.', '[]', 'approved'),
  (3003, 1003, NULL, 5, 'Excellent commercial cleaning for our retail store.', 1, datetime('now', '-16 days'), datetime('now'), 2003, 'Excellent commercial cleaning for our retail store in Umhlanga. The floors are spotless and the windows are crystal clear. Our customers have even commented on how clean the shop looks!', '[]', 'approved'),
  (3004, 1004, NULL, 3, 'Decent service but arrived 15 minutes late.', 1, datetime('now', '-53 days'), datetime('now'), 2004, 'Decent cleaning service. The quality was good once they got started, but they arrived 15 minutes late which was inconvenient. The deep clean itself was thorough and my apartment looks much better.', '[]', 'approved'),
  (3005, 1005, NULL, 5, 'Absolutely love the recurring service. Consistent quality every week.', 1, datetime('now', '-11 days'), datetime('now'), 2005, 'Absolutely love the recurring service. Consistent quality every single week. The same friendly cleaner who knows exactly what I like. My home in Stellenbosch has never looked better!', '[]', 'approved'),
  (3006, 1001, NULL, 4, 'Maintenance clean was quick and effective. Good value for money.', 1, datetime('now', '-9 days'), datetime('now'), 2006, 'Maintenance clean was quick and effective. Good value for money. They focus on the high-traffic areas which is exactly what I need between deep cleans. Booking process is super easy too.', '[]', 'approved'),
  (3007, 1003, NULL, 5, 'Second booking and just as impressed. Highly recommend for businesses.', 1, datetime('now', '-4 days'), datetime('now'), 2007, 'Second booking with Scratch Solid and just as impressed as the first time. They understand commercial spaces and work around our operating hours. Highly recommend for any business in Durban.', '[]', 'approved'),
  (3008, 1002, NULL, 4, 'Reliable and trustworthy. Left my keys with them and everything was perfect.', 1, datetime('now', '-7 days'), datetime('now'), 2008, 'Reliable and trustworthy service. I had to leave my keys with them while at work and everything was perfect when I got home. House was secure, clean and tidy. Great communication throughout.', '[]', 'approved');
